pub fn get_one<T: 'static>(&self, name: &str) -> Result<Option<&T>, MatchesError> {
    let id = Id::from(name);
    let value = match self.try_get_arg(&id)?.and_then(|a| a.first()) {
        Some(value) => value,
        None => {
            return Ok(None);
        }
    };
    value
        .downcast_ref::<T>()
        .map(Some)
        .ok_or_else(|| MatchesError::Downcast {
            actual: value.type_id(),
            expected: AnyValueId::of::<T>(),
        })
}

