pub fn min_by<F>(self, mut compare: F) -> HashMap<K, V>
    where F: FnMut(&K, &V, &V) -> Ordering,
{
    self.fold_first(|acc, key, val| match compare(key, &acc, &val) {
        Ordering::Less | Ordering::Equal => acc,
        Ordering::Greater => val
    })
}

