pub(super) fn new(i: I, j: J) -> Self {
    InterleaveShortest {
        interleave: if i.len() <= j.len() {
            // take equal lengths from both iterators
            let n = i.len();
            i.take(n).interleave(j.take(n))
        } else {
            // take one extra item from the first iterator
            let n = j.len();
            i.take(n + 1).interleave(j.take(n))
        },
    }
}

