pub fn from_hms_nano_opt(hour: u32, min: u32, sec: u32, nano: u32) -> Option<NaiveTime> {
    if hour >= 24 || min >= 60 || sec >= 60 || nano >= 2_000_000_000 { return None; }
    let secs = hour * 3600 + min * 60 + sec;
    Some(NaiveTime { secs: secs, frac: nano })
}

