fn fibonacci_split_recursive(b: &mut test::Bencher) {
    fn fib(n: u32) -> u32 {
        use rayon::iter::ParallelIterator;

        rayon::iter::split(n, |n| {
                if n < 2 {
                    (n, None)
                } else {
                    (n - 2, Some(n - 1))
                }
            })
            .map(fib_recursive)
            .sum()
    }

    b.iter(|| assert_eq!(fib(test::black_box(N)), FN));
}

