pub const fn new(secs: i64, nanos: u32) -> Option<TimeDelta> {
    if secs < MIN.secs
        || secs > MAX.secs
        || nanos >= 1_000_000_000
        || (secs == MAX.secs && nanos > MAX.nanos as u32)
        || (secs == MIN.secs && nanos < MIN.nanos as u32)
    {
        return None;
    }
    Some(TimeDelta { secs, nanos: nanos as i32 })
}

